import pymysql
import os
from flask import jsonify

def search_database(request):
    connection = None
    try:
        connection = pymysql.connect(
            host=os.environ.get('DB_HOST', '127.0.0.1'),
            user=os.environ.get('DB_USER', 'root'),
            password=os.environ.get('DB_PASSWORD', ''),
            database=os.environ.get('DB_NAME', 'mydb'),
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor
        )
        
        request_json = request.get_json(silent=True)
        request_args = request.args
        
        table = None
        conditions = []
        order_by = None
        limit = None
        
        if request_json:
            table = request_json.get('table', 'users')
            filters = request_json.get('filters', {})
            order_by = request_json.get('order_by')
            limit = request_json.get('limit')
            
            for key, value in filters.items():
                if isinstance(value, str):
                    conditions.append(f"{key} = '{value}'")
                else:
                    conditions.append(f"{key} = {value}")
        else:
            table = request_args.get('table', 'users')
            
            for key, value in request_args.items():
                if key not in ['table', 'order_by', 'limit']:
                    conditions.append(f"{key} = '{value}'")
            
            order_by = request_args.get('order_by')
            limit = request_args.get('limit')
        
        query = f"SELECT * FROM {table}"
        
        if conditions:
            where_clause = " AND ".join(conditions)
            query += f" WHERE {where_clause}"
        
        if order_by:
            query += f" ORDER BY {order_by}"
        
        if limit:
            query += f" LIMIT {limit}"
        
        with connection.cursor() as cursor:
            cursor.execute(query)
            results = cursor.fetchall()
        
        return jsonify({
            'success': True,
            'query': query,
            'count': len(results),
            'data': results
        })
    
    except Exception as e:
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500
    
    finally:
        if connection:
            connection.close()